import React from "react";
import { motion } from "framer-motion";
import "bootstrap/dist/css/bootstrap.min.css";
import "./App.css";

export default function LandingPage() {
  return (
    <div className="bg-surface">
      {/* Navbar - Custom Styled Bootstrap Navbar */}
      <nav
        className="navbar navbar-expand-lg fixed-top border-bottom border-white/5"
        style={{
          background: "rgba(16, 20, 26, 0.8)",
          backdropFilter: "blur(15px)",
        }}
      >
        <div className="container py-2">
          <a
            className="navbar-brand fw-black fs-3 text-info"
            href="#"
            style={{
              fontFamily: "var(--headline-font)",
              letterSpacing: "-1px",
            }}
          >
            Techvruk
          </a>
          <div className="collapse navbar-collapse" id="nav">
            <ul className="navbar-nav ms-auto gap-4">
              <li className="nav-item">
                <a
                  className="nav-link text-uppercase fw-bold small text-secondary"
                  href="#programs"
                >
                  Programs
                </a>
              </li>
              <li className="nav-item">
                <a
                  className="nav-link text-uppercase fw-bold small text-secondary"
                  href="#community"
                >
                  Community
                </a>
              </li>
            </ul>
            <button className="btn btn-techvruk ms-lg-4 px-4 py-2 text-uppercase small">
              Join Now
            </button>
          </div>
        </div>
      </nav>

      {/* Hero Section */}
      <section
        className="position-relative d-flex align-items-center justify-content-center text-center overflow-hidden"
        style={{ minHeight: "100vh" }}
      >
        {/* Background Blobs */}
        <div className="position-absolute w-100 h-100" style={{ zIndex: 0 }}>
          <div
            className="position-absolute rounded-circle"
            style={{
              top: "10%",
              left: "10%",
              width: "400px",
              height: "400px",
              background: "rgba(195, 245, 255, 0.08)",
              filter: "blur(120px)",
            }}
          ></div>
          <div
            className="position-absolute rounded-circle"
            style={{
              bottom: "10%",
              right: "10%",
              width: "400px",
              height: "400px",
              background: "rgba(216, 185, 255, 0.08)",
              filter: "blur(120px)",
            }}
          ></div>
        </div>

        <div className="container position-relative" style={{ zIndex: 1 }}>
          <motion.span
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            className="badge rounded-pill px-3 py-2 mb-4 border border-info/20"
            style={{
              background: "rgba(0, 229, 255, 0.1)",
              color: "var(--primary)",
              letterSpacing: "3px",
            }}
          >
            ENGINEERING EXCELLENCE
          </motion.span>

          <motion.h1
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            className="display-1 fw-black mb-4 text-white"
            style={{
              fontFamily: "var(--headline-font)",
              letterSpacing: "-3px",
            }}
          >
            Build the Future with{" "}
            <span className="text-gradient">Techvruk</span>
          </motion.h1>

          <p
            className="lead mx-auto mb-5 text-on-surface-variant"
            style={{ maxWidth: "700px" }}
          >
            Empowering engineers through innovation, training, and
            collaboration. Join a community where code meets mechanical
            precision.
          </p>

          <div className="d-flex flex-column flex-sm-row justify-content-center gap-3">
            <button className="btn btn-techvruk btn-lg px-5 py-3">
              Join Now
            </button>
            <button className="btn btn-outline-info btn-lg px-5 py-3 text-white border-info">
              Explore Programs
            </button>
          </div>
        </div>
      </section>

      {/* Value Proposition - Bootstrap Grid + Techvruk Glass Cards */}
      <section className="py-5" style={{ backgroundColor: "#161a20" }}>
        <div className="container py-5">
          <div className="row g-4">
            {[
              { title: "Innovation Contests", icon: "rocket_launch" },
              { title: "Industry Training", icon: "school" },
              { title: "Awards & Recognition", icon: "workspace_premium" },
              { title: "Networking", icon: "hub" },
            ].map((item, i) => (
              <div key={i} className="col-md-6 col-lg-3">
                <div className="glass-panel p-4 h-100 rounded-4 text-start transition-all">
                  <span className="material-symbols-outlined display-5 text-info mb-4">
                    {item.icon}
                  </span>
                  <h3
                    className="h5 fw-bold text-white mb-3"
                    style={{ fontFamily: "var(--headline-font)" }}
                  >
                    {item.title}
                  </h3>
                  <p className="small text-on-surface-variant">
                    Solve real-world engineering challenges and push the
                    boundaries of technology.
                  </p>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* Stats Section - Dark Minimalist */}
      <section className="py-5 bg-black border-top border-bottom border-dark">
        <div className="container py-4">
          <div className="row text-center g-4">
            <div className="col-md-4">
              <h2
                className="display-4 fw-black text-info"
                style={{ fontFamily: "var(--headline-font)" }}
              >
                10,000+
              </h2>
              <p className="text-uppercase small tracking-widest text-secondary">
                Engineers Empowered
              </p>
            </div>
            <div className="col-md-4">
              <h2
                className="display-4 fw-black text-primary"
                style={{ fontFamily: "var(--headline-font)" }}
              >
                200+
              </h2>
              <p className="text-uppercase small tracking-widest text-secondary">
                Industry Events
              </p>
            </div>
